# Basic DFA: Accepts binary strings ending with '0'
# States: q0 (start), q1 (accepting)
# Alphabet: {0, 1}

class SimpleDFA:
    def __init__(self):
        self.states = {'q0', 'q1'}
        self.alphabet = {'0', '1'}
        self.start_state = 'q0'
        self.accept_states = {'q1'}
        self.current_state = self.start_state

        # Transition function: delta(state, input) -> next_state
        self.transitions = {
            ('q0', '0'): 'q1',  # After seeing 0, move to accepting state
            ('q0', '1'): 'q0',  # After seeing 1, stay in non-accepting
            ('q1', '0'): 'q1',  # Keep accepting after more 0s
            ('q1', '1'): 'q0'   # 1 resets us to non-accepting
        }

    def reset(self):
        self.current_state = self.start_state

    def process_input(self, input_string):
        self.reset()
        for symbol in input_string:
            if symbol not in self.alphabet:
                raise ValueError(f"Invalid symbol '{symbol}' in input")
            self.current_state = self.transitions[(self.current_state, symbol)]
        return self.current_state in self.accept_states

# Test the DFA
dfa = SimpleDFA()

test_cases = ['0', '10', '110', '1010', '111', '100', '01']
print("String\t\t | Accepts?")
print("-" * 25)
for s in test_cases:
    result = dfa.process_input(s)
    print(f"'{s}'\t\t | {result}")

# DFA: Accepts binary strings with EVEN number of 0s
# States: q_even (accepting), q_odd (non-accepting)
# Alphabet: {0, 1}

class EvenZerosDFA:
    def __init__(self):
        self.states = {'q_even', 'q_odd'}
        self.alphabet = {'0', '1'}
        self.start_state = 'q_even'  # 0 zeros is even
        self.accept_states = {'q_even'}
        self.current_state = self.start_state

        # Transition function
        self.transitions = {
            ('q_even', '0'): 'q_odd',   # Even + 0 = Odd
            ('q_even', '1'): 'q_even',  # Even + 1 = Even
            ('q_odd', '0'): 'q_even',   # Odd + 0 = Even
            ('q_odd', '1'): 'q_odd'     # Odd + 1 = Odd
        }

    def reset(self):
        self.current_state = self.start_state

    def process_input(self, input_string):
        self.reset()
        zero_count = 0
        for symbol in input_string:
            if symbol not in self.alphabet:
                raise ValueError(f"Invalid symbol '{symbol}'")
            self.current_state = self.transitions[(self.current_state, symbol)]
            if symbol == '0':
                zero_count += 1
        print(f"Number of 0s: {zero_count} (even: {zero_count % 2 == 0})")
        return self.current_state in self.accept_states

# Test the DFA
dfa = EvenZerosDFA()

test_cases = ['', '1', '11', '111', '0', '00', '10', '100', '1010', '1100']
print("String\t\t | Accepts? | Count")
print("-" * 35)
for s in test_cases:
    result = dfa.process_input(s if s else 'ε')
    display_str = s if s else 'ε'
    print(f"'{display_str}'\t\t | {result}")
